There are some extra quotes in there, which is causing this strange output.

```go
package main

import (
	"fmt"
	"log"
	"time"
)

func main() {
	t, err := time.Parse("\"2006-01-02T15:04:05Z07:00\"", "1581706310")
	if err != nil {
		log.Fatal(err)
	}
	fmt.Println(t)
}

```

